import React, { useState, useEffect } from 'react';
import { generateTextVisual } from '../utils/layoutUtils';

interface LayoutStats {
  effort: number;
  distance: number;
  same_finger_bigrams_pct: number;
  roll_in_pct: number;
  roll_out_pct: number;
  trigram_alt_pct: number;
}

const DesignerPage: React.FC = () => {
  const [textContent, setTextContent] = useState('` 1 2 3 4 5 6 7 8 9 0 - =\nq w e r t y u i o p [ ]\na s d f g h j k l ; \'\nz x c v b n m , . /');
  const [currentLayout, setCurrentLayout] = useState<Record<string, string>>({});
  const [stats, setStats] = useState<LayoutStats | null>(null);
  const [showFingerColors, setShowFingerColors] = useState(true);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Finger color mapping
  const fingerColors: Record<string, string> = {
    'LP': 'bg-red-200 dark:bg-red-800 text-red-800 dark:text-red-200',    // Left Pinky
    'LR': 'bg-orange-200 dark:bg-orange-800 text-orange-800 dark:text-orange-200', // Left Ring
    'LM': 'bg-yellow-200 dark:bg-yellow-800 text-yellow-800 dark:text-yellow-200', // Left Middle
    'LI': 'bg-green-200 dark:bg-green-800 text-green-800 dark:text-green-200',   // Left Index
    'RI': 'bg-blue-200 dark:bg-blue-800 text-blue-800 dark:text-blue-200',    // Right Index
    'RM': 'bg-indigo-200 dark:bg-indigo-800 text-indigo-800 dark:text-indigo-200', // Right Middle
    'RR': 'bg-purple-200 dark:bg-purple-800 text-purple-800 dark:text-purple-200', // Right Ring
    'RP': 'bg-pink-200 dark:bg-pink-800 text-pink-800 dark:text-pink-200'     // Right Pinky
  };

  // Finger mapping for standard QWERTY positions
  const fingerMap: Record<string, string> = {
    // Top row
    '`': 'LP', '1': 'LP', '2': 'LR', '3': 'LM', '4': 'LI', '5': 'LI',
    '6': 'RI', '7': 'RI', '8': 'RM', '9': 'RR', '0': 'RP', '-': 'RP', '=': 'RP',
    // Second row
    'q': 'LP', 'w': 'LR', 'e': 'LM', 'r': 'LI', 't': 'LI',
    'y': 'RI', 'u': 'RI', 'i': 'RM', 'o': 'RR', 'p': 'RP', '[': 'RP', ']': 'RP',
    // Third row
    'a': 'LP', 's': 'LR', 'd': 'LM', 'f': 'LI', 'g': 'LI',
    'h': 'RI', 'j': 'RI', 'k': 'RM', 'l': 'RR', ';': 'RP', '\'': 'RP',
    // Fourth row
    'z': 'LP', 'x': 'LR', 'c': 'LM', 'v': 'LI', 'b': 'LI',
    'n': 'RI', 'm': 'RI', ',': 'RM', '.': 'RR', '/': 'RP'
  };

  // Parse text content into layout object
  const parseTextToLayout = (text: string): Record<string, string> => {
    const lines = text.split('\n');
    const layout: Record<string, string> = {};
    
    const keyPositions = [
      ['`', '1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
      ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
      ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', '\''],
      ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/']
    ];
    
    lines.forEach((line, rowIndex) => {
      if (rowIndex < keyPositions.length) {
        const chars = line.trim().split(/\s+/).filter(char => char);
        const positions = keyPositions[rowIndex];
        
        chars.forEach((char, charIndex) => {
          if (charIndex < positions.length) {
            layout[positions[charIndex]] = char;
          }
        });
      }
    });
    
    return layout;
  };

  // Analyze layout function
  const analyzeLayout = async (layout: Record<string, string>) => {
    if (Object.keys(layout).length === 0) return;
    
    setIsAnalyzing(true);
    try {
      const response = await fetch('/api/analyze', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ layout_data: { keys: layout } }),
      });
      
      if (response.ok) {
        const data = await response.json();
        setStats(data);
      } else {
        // Fallback to mock analysis
        setStats({
          effort: Math.random() * 0.5 + 1.0, // 1.0 - 1.5
          distance: Math.random() * 0.8 + 0.8, // 0.8 - 1.6
          same_finger_bigrams_pct: Math.random() * 5 + 1, // 1 - 6
          roll_in_pct: Math.random() * 10 + 10, // 10 - 20
          roll_out_pct: Math.random() * 8 + 5, // 5 - 13
          trigram_alt_pct: Math.random() * 15 + 15 // 15 - 30
        });
      }
    } catch (error) {
      console.error('Error analyzing layout:', error);
      // Mock stats for demonstration
      setStats({
        effort: Math.random() * 0.5 + 1.0,
        distance: Math.random() * 0.8 + 0.8,
        same_finger_bigrams_pct: Math.random() * 5 + 1,
        roll_in_pct: Math.random() * 10 + 10,
        roll_out_pct: Math.random() * 8 + 5,
        trigram_alt_pct: Math.random() * 15 + 15
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleTextChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setTextContent(e.target.value);
  };

  // Update layout when text changes
  useEffect(() => {
    const layout = parseTextToLayout(textContent);
    setCurrentLayout(layout);
    // Debounce analysis
    const timeoutId = setTimeout(() => {
      analyzeLayout(layout);
    }, 500);
    
    return () => clearTimeout(timeoutId);
  }, [textContent]);

  // Render a single key with finger coloring
  const renderKey = (char: string, position: string) => {
    const finger = fingerMap[position];
    const colorClass = showFingerColors && finger ? fingerColors[finger] : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200';
    
    return (
      <div
        key={position}
        className={`flex items-center justify-center min-w-[2.5rem] h-10 rounded-md border border-gray-300 dark:border-gray-600 font-mono text-sm font-medium ${colorClass}`}
      >
        {char || position}
      </div>
    );
  };

  // Get metric color based on value
  const getMetricColor = (value: number | undefined, good: number, bad: number, lowerIsBetter: boolean = true) => {
    if (value === undefined) return 'text-gray-400';
    if (lowerIsBetter) {
      return value <= good ? 'text-green-500' : value >= bad ? 'text-red-500' : 'text-yellow-500';
    } else {
      return value >= good ? 'text-green-500' : value <= bad ? 'text-red-500' : 'text-yellow-500';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
      <div className="max-w-4xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold bg-gradient-to-r from-purple-600 to-blue-600 bg-clip-text text-transparent mb-4">
            Simple Layout Designer
          </h1>
          <p className="text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
            Edit your keyboard layout as text and see a live preview below.
          </p>
        </div>

        <div className="space-y-8">
          {/* Text Editor */}
          <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
            <h2 className="text-2xl font-bold mb-4">Layout Editor</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-2">
                  Edit your keyboard layout (each row on a new line, characters separated by spaces):
                </label>
                <textarea
                  value={textContent}
                  onChange={handleTextChange}
                  className="w-full h-32 p-4 font-mono text-lg border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent bg-gray-50 dark:bg-gray-700 resize-none"
                  placeholder="` 1 2 3 4 5 6 7 8 9 0 - =\nq w e r t y u i o p [ ]\na s d f g h j k l ; '\nz x c v b n m , . /"
                />
              </div>
              <div className="text-sm text-gray-600 dark:text-gray-400">
                <p><strong>Instructions:</strong></p>
                <ul className="list-disc list-inside space-y-1">
                  <li>Each line represents a row on the keyboard</li>
                  <li>Characters are separated by spaces</li>
                  <li>Changes are reflected in the preview below in real-time</li>
                </ul>
              </div>
            </div>
          </div>

          {/* Live Preview */}
          <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
            <h2 className="text-2xl font-bold mb-4">Live Preview</h2>
            <div className="bg-gray-100 dark:bg-gray-700 p-6 rounded-xl">
              <div className="bg-white dark:bg-gray-900 p-6 rounded-lg border border-gray-300 dark:border-gray-600">
                <pre className="font-mono text-xl leading-relaxed text-center whitespace-pre-line text-gray-800 dark:text-gray-200">
                  {textContent}
                </pre>
              </div>
              <div className="mt-4 text-sm text-gray-600 dark:text-gray-400 text-center">
                This is how your keyboard layout looks. Edit the text above to see changes here.
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DesignerPage;
